hudson.tasks.Shell.command:
#!/bin/bash set -e
source_scripts_folder="${JENKINS_HOME}/workspace/Bash_Functions/" for script_file in "$source_scripts_folder"*.sh; do chmod +x "$script_file" if [ -f "$script_file" ] && [ -x "$script_file" ]; then echo "sourcing $script_file" source "$script_file" fi done
cd app-infrastructure/template-renderer
echo "Attempting to download visualization template from S3..." aws s3 cp "s3://${stack_s3_bucket}/configs/pic-sure-visualization/templates/${TARGET_STACK}/visualization.env.tftpl" \ templates/visualization.env.tftpl \ && echo "Using stack-specific S3 template for visualization.env.tftpl" \ || { aws s3 cp "s3://${stack_s3_bucket}/configs/pic-sure-visualization/templates/visualization.env.tftpl" \ templates/visualization.env.tftpl \ && echo "Using shared S3 template for visualization.env.tftpl" \ || echo "No S3 template found, using repo version of visualization.env.tftpl"; }
terraform init -input=false
terraform apply -auto-approve -input=false \ -var="stack_s3_bucket=${stack_s3_bucket}" \ -var="environment_name=${environment_name}" \ -var="target_stack=${TARGET_STACK}" \ -var="env_private_dns_name=${env_private_dns_name}" \ -var="render_auth_hpds=false" \ -var="render_open_hpds=false" \ -var="render_visualization=true"
